                    int t_index_y =  BLOCK_SIZE - tx;

                    int val_diag = l_input_itemsets_l[(t_index_y-1) + (t_index_x-1)*(BLOCK_SIZE+1)] + l_reference_l[(t_index_y-1) + (t_index_x-1)*BLOCK_SIZE];
