                    int val_up   = l_input_itemsets_l[(t_index_y-1) + (t_index_x)*(BLOCK_SIZE+1)] - penalty;

                    l_input_itemsets_l[t_index_y + t_index_x*(BLOCK_SIZE+1)] = maximum(val_diag, val_left, val_up);
                }
                // Barrier: implicit
            }

            // Barrier

            // Write back only for the simulated tx? 
            // In OpenCL, all threads write.
            // Here we are looping tx, so we write for each tx.
            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                input_itemsets_d[index + cols * ty] = l_input_itemsets_l[(ty+1) + (tx+1)*(BLOCK_SIZE+1)];
        }
    }
}

void nw_kernel2( int  * reference_d, 
		   int  * input_itemsets_d, 
		   int  * output_itemsets_d, 
           int cols,
           int penalty,
           int blk,
           int block_width,
           int worksize,
           int offset_r,
           int offset_c
    )
{  
    int local_input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
    int local_reference_l[BLOCK_SIZE*BLOCK_SIZE];

    #pragma omp parallel for
    for(int bx = 0; bx < blk; bx++) {

        int l_input_itemsets_l[(BLOCK_SIZE+1)*(BLOCK_SIZE+1)];
        int l_reference_l[BLOCK_SIZE*BLOCK_SIZE];

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {

            int base = offset_r * cols + offset_c;
            int b_index_x = bx + block_width - blk;
            int b_index_y = block_width - bx -1;

            int index   =   base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
            int index_n   = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
