            int index_nw =  base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

            if (tx == 0)
                l_input_itemsets_l[0 + 0 * (BLOCK_SIZE+1)] = input_itemsets_d[index_nw];

            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                l_reference_l[ty + tx * BLOCK_SIZE] =  reference_d[index + cols * ty];

            // barrier

            l_input_itemsets_l[(tx + 1) + 0 * (BLOCK_SIZE+1)] = input_itemsets_d[index_w + cols * tx];

            // barrier

            l_input_itemsets_l[0 + (tx + 1) * (BLOCK_SIZE+1)] = input_itemsets_d[index_n];

            // barrier

            for( int m = 0 ; m < BLOCK_SIZE ; m++){
                if ( tx <= m ){
                    int t_index_x =  tx + 1;
                    int t_index_y =  m - tx + 1;

                    int val_diag = l_input_itemsets_l[(t_index_y-1) + (t_index_x-1)*(BLOCK_SIZE+1)] + l_reference_l[(t_index_y-1) + (t_index_x-1)*BLOCK_SIZE];
                    int val_left = l_input_itemsets_l[(t_index_y) + (t_index_x-1)*(BLOCK_SIZE+1)] - penalty;
                    int val_up   = l_input_itemsets_l[(t_index_y-1) + (t_index_x)*(BLOCK_SIZE+1)] - penalty;

                    l_input_itemsets_l[t_index_y + t_index_x*(BLOCK_SIZE+1)] = maximum(val_diag, val_left, val_up);
                }
            }

            for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){
                if ( tx <= m){
                    int t_index_x =  tx + BLOCK_SIZE - m ;
                    int t_index_y =  BLOCK_SIZE - tx;

                    int val_diag = l_input_itemsets_l[(t_index_y-1) + (t_index_x-1)*(BLOCK_SIZE+1)] + l_reference_l[(t_index_y-1) + (t_index_x-1)*BLOCK_SIZE];
                    int val_left = l_input_itemsets_l[(t_index_y) + (t_index_x-1)*(BLOCK_SIZE+1)] - penalty;
                    int val_up   = l_input_itemsets_l[(t_index_y-1) + (t_index_x)*(BLOCK_SIZE+1)] - penalty;

                    l_input_itemsets_l[t_index_y + t_index_x*(BLOCK_SIZE+1)] = maximum(val_diag, val_left, val_up);
                }
            }

            for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
                input_itemsets_d[index + ty * cols] = l_input_itemsets_l[(ty+1) + (tx+1)*(BLOCK_SIZE+1)];
        }
    }
